import React, { useState, useEffect } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { ShoppingCart, Bell, Menu, X, LogOut, ChevronDown, User } from 'lucide-react';
import { useAuth } from '../context/AuthContext';
import { useCart } from '../context/CartContext';
import API from '../utils/api';

/* ── Inline logo SVG ── */
function FitnationLogo({ size = 36 }) {
  return (
    <svg width={size} height={size} viewBox="0 0 100 100" fill="none">
      <circle cx="50" cy="50" r="44" stroke="url(#nr)" strokeWidth="5" fill="none"/>
      <rect x="4"  y="46" width="18" height="8" rx="3" fill="url(#nb)"/>
      <rect x="2"  y="42" width="6"  height="16" rx="2" fill="#93c5fd"/>
      <rect x="78" y="46" width="18" height="8" rx="3" fill="url(#nb)"/>
      <rect x="92" y="42" width="6"  height="16" rx="2" fill="#93c5fd"/>
      <polygon points="50,18 28,75 72,75" fill="url(#nt)"/>
      <polygon points="50,40 40,65 60,65" fill="white"/>
      <defs>
        <linearGradient id="nt" x1="28" y1="18" x2="72" y2="75" gradientUnits="userSpaceOnUse">
          <stop offset="0%" stopColor="#3b82f6"/><stop offset="100%" stopColor="#1d4ed8"/>
        </linearGradient>
        <linearGradient id="nr" x1="0" y1="0" x2="100" y2="100" gradientUnits="userSpaceOnUse">
          <stop offset="0%" stopColor="#93c5fd"/><stop offset="100%" stopColor="#64748b"/>
        </linearGradient>
        <linearGradient id="nb" x1="0" y1="0" x2="1" y2="0" gradientUnits="userSpaceOnUse">
          <stop offset="0%" stopColor="#93c5fd"/><stop offset="100%" stopColor="#64748b"/>
        </linearGradient>
      </defs>
    </svg>
  );
}

const navLinks = [
  { label: 'Home',            path: '/' },
  { label: 'Exercises',       path: '/exercises' },
  { label: 'Diet Plans',      path: '/diet' },
  { label: 'Transformations', path: '/transformations' },
  { label: 'Store',           path: '/store' },
  { label: 'About',           path: '/about' },
  { label: 'Enquiry',         path: '/enquiry' },
];

export default function Navbar() {
  const { user, logout } = useAuth();
  const { count } = useCart();
  const navigate = useNavigate();
  const location = useLocation();
  const [mobileOpen, setMobileOpen] = useState(false);
  const [scrolled, setScrolled]     = useState(false);
  const [unread, setUnread]         = useState(0);

  useEffect(() => {
    const handler = () => setScrolled(window.scrollY > 10);
    window.addEventListener('scroll', handler);
    return () => window.removeEventListener('scroll', handler);
  }, []);

  useEffect(() => {
    if (user) {
      API.get('/notifications').then(r => setUnread(r.data.filter(n => !n.isRead).length)).catch(() => {});
    }
  }, [user, location.pathname]);

  const handleLogout = () => { logout(); navigate('/'); setMobileOpen(false); };

  return (
    <motion.nav
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${scrolled ? 'nav-light' : 'bg-white/90 backdrop-blur-sm'}`}
      initial={{ y: -64 }}
      animate={{ y: 0 }}
      transition={{ duration: 0.45, ease: [0.16,1,0.3,1] }}
    >
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-16">

          {/* Logo */}
          <Link to="/" className="flex items-center gap-2.5 flex-shrink-0">
            <FitnationLogo size={36} />
            <div className="leading-none">
              <div className="text-gray-900 font-black gym-font text-xl tracking-wider">FITNATION</div>
              <div className="text-blue-600 font-bold text-[10px] tracking-widest -mt-0.5">BY AJEET</div>
            </div>
          </Link>

          {/* Desktop links */}
          <div className="hidden lg:flex items-center gap-1">
            {navLinks.map(l => (
              <Link
                key={l.path} to={l.path}
                className={`px-3 py-2 rounded-lg text-sm font-medium transition-all ${
                  location.pathname === l.path
                    ? 'text-blue-600 bg-blue-50'
                    : 'text-gray-600 hover:text-blue-600 hover:bg-blue-50'
                }`}
              >
                {l.label}
              </Link>
            ))}
          </div>

          {/* Right actions */}
          <div className="hidden lg:flex items-center gap-2">
            <Link to="/cart" className="relative p-2.5 rounded-xl text-gray-500 hover:text-blue-600 hover:bg-blue-50 transition-all">
              <ShoppingCart size={20} />
              {count > 0 && (
                <span className="absolute -top-0.5 -right-0.5 w-5 h-5 bg-blue-600 text-white text-[10px] font-bold rounded-full flex items-center justify-center">{count}</span>
              )}
            </Link>

            {user ? (
              <>
                <Link to="/notifications" className="relative p-2.5 rounded-xl text-gray-500 hover:text-blue-600 hover:bg-blue-50 transition-all">
                  <Bell size={20} />
                  {unread > 0 && (
                    <span className="absolute -top-0.5 -right-0.5 w-5 h-5 bg-red-500 text-white text-[10px] font-bold rounded-full flex items-center justify-center">{unread}</span>
                  )}
                </Link>
                <div className="h-6 w-px bg-gray-200 mx-1" />
                <div className="flex items-center gap-2 px-2 py-1 rounded-xl hover:bg-gray-50 transition-all">
                  <div className="w-8 h-8 rounded-full bg-gradient-to-br from-blue-500 to-cyan-500 flex items-center justify-center text-white font-bold text-sm">
                    {user.name?.[0]?.toUpperCase()}
                  </div>
                  <div className="leading-none">
                    <div className="text-gray-800 text-xs font-semibold">{user.name?.split(' ')[0]}</div>
                    <div className="text-blue-600 text-[10px] capitalize">{user.role}</div>
                  </div>
                </div>
                {(user.role === 'admin' || user.role === 'trainer') && (
                  <Link to="/admin" className="btn-fire text-xs px-3 py-2">Admin Panel</Link>
                )}
                {user.role === 'member' && (
                  <Link to="/dashboard" className="btn-fire text-xs px-3 py-2">Dashboard</Link>
                )}
                <button onClick={handleLogout} className="p-2.5 rounded-xl text-gray-400 hover:text-red-500 hover:bg-red-50 transition-all">
                  <LogOut size={18} />
                </button>
              </>
            ) : (
              <Link to="/login" className="btn-fire text-sm px-5 py-2.5">Sign In</Link>
            )}
          </div>

          {/* Mobile toggle */}
          <button
            onClick={() => setMobileOpen(!mobileOpen)}
            className="lg:hidden p-2 rounded-xl text-gray-600 hover:bg-gray-100 transition-all"
          >
            {mobileOpen ? <X size={22} /> : <Menu size={22} />}
          </button>
        </div>
      </div>

      {/* Mobile menu */}
      <AnimatePresence>
        {mobileOpen && (
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: 'auto' }}
            exit={{ opacity: 0, height: 0 }}
            className="lg:hidden bg-white border-t border-gray-100 shadow-lg"
          >
            <div className="px-4 py-4 space-y-1">
              {navLinks.map(l => (
                <Link
                  key={l.path} to={l.path} onClick={() => setMobileOpen(false)}
                  className={`block px-4 py-3 rounded-xl text-sm font-medium transition-all ${
                    location.pathname === l.path ? 'text-blue-600 bg-blue-50' : 'text-gray-600 hover:bg-gray-50'
                  }`}
                >
                  {l.label}
                </Link>
              ))}
              <div className="pt-2 flex items-center gap-3 border-t border-gray-100 mt-2">
                <Link to="/cart" onClick={() => setMobileOpen(false)} className="flex items-center gap-2 text-sm text-gray-600 px-4 py-2">
                  <ShoppingCart size={16} /> Cart {count > 0 && `(${count})`}
                </Link>
              </div>
              {user ? (
                <button onClick={handleLogout} className="w-full text-left px-4 py-2 text-sm text-red-500 flex items-center gap-2">
                  <LogOut size={16} /> Logout
                </button>
              ) : (
                <Link to="/login" onClick={() => setMobileOpen(false)} className="block">
                  <button className="btn-fire w-full justify-center py-3 mt-2">Sign In</button>
                </Link>
              )}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.nav>
  );
}
